#include <bits/stdc++.h>
using namespace std;
const int N=2e5+5;
int n,k,q,dist[N],f[N][19],dep[N];
bool t[N];
vector<int> g[N];
void dfs1(int x,int fa){
	if(t[x])
		dist[x]=0;
	else
		dist[x]=1e9;
	dep[x]=dep[fa]+1;
	int len=g[x].size();
	for(int i=0;i<len;i++)
		if(g[x][i]!=fa){
			int v=g[x][i];
			f[v][0]=x;
			for(int j=1;f[f[v][j-1]][j-1];j++)
				f[v][j]=f[f[v][j-1]][j-1];
			dfs1(v,x);
			dist[x]=min(dist[x],dist[v]+1);
		}
}
void dfs2(int x,int fa){
	if(fa)
		dist[x]=min(dist[x],dist[fa]+1);
	int len=g[x].size();
	for(int i=0;i<len;i++)
		if(g[x][i]!=fa)
			dfs2(g[x][i],x);
}
int LCA(int x,int y){
	if(dep[x]<dep[y])
		swap(x,y);
	int ans=0;
	for(int i=18;i>=0;i--)
		if(dep[f[x][i]]>=dep[y])
			x=f[x][i],ans+=1<<i;
	if(x==y)
		return ans;
	for(int i=18;i>=0;i--)
		if(f[x][i]!=f[y][i])
			x=f[x][i],y=f[y][i],ans+=1<<i+1;
	return ans+2;
}
int main(){
	scanf("%d%d%d",&n,&k,&q);
	for(int i=1,u,v;i<n;i++){
		scanf("%d%d",&u,&v);
		g[u].push_back(v);
		g[v].push_back(u);
	}
	while(k--){
		int u;
		scanf("%d",&u);
		t[u]=1;
	}
	dfs1(1,0);
	dfs2(1,0);
	//for(int i=1;i<=n;i++)
		//printf("%d\n",dist[i]);
	while(q--){
		int u,v;
		scanf("%d%d",&u,&v);
		printf("%d\n",min(LCA(u,v),dist[u]+dist[v]));
	}
	return 0;
}
